  INSERT INTO knowledge_sop_steps (sop_id, step_number, title, content, step_type, order_index) VALUES
    (v_sop_id, 1, 'Objetivo', E'Estabelecer diretrizes claras de conduta que orientam o comportamento de todos os membros da TBO — sócios, colaboradores, freelancers e parceiros — no relacionamento interno, com clientes e com o mercado.\n\nEste código não é burocracia: é o contrato tácito de como a TBO opera. Violações comprometem a reputação da agência e a confiança dos clientes.', 'step', 0),
    (v_sop_id, 2, 'Escopo', E'**Quem se aplica:** 100% dos membros da TBO — CLT, PJ, freelancer, estagiário, parceiro com acesso a sistemas ou projetos\n**Quando se aplica:** Em todos os contextos profissionais — presenciais, digitais, internos e externos\n**Vigência:** Imediata ao onboarding, com revisão anual em janeiro', 'step', 1),
    (v_sop_id, 3, 'RACI', E'| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Definir e revisar o código | Marco + Ruy | Marco + Ruy | Time sênior | Todo o time |\n| Comunicar em onboarding | Operações / RH | Marco | — | Todo o time |\n| Receber relatos de violação | Marco ou Ruy | — | — | Parte afetada |\n| Investigar e aplicar consequências | Marco + Ruy | Marco + Ruy | Assessor jurídico | Envolvidos |\n| Revisão anual | Marco | Ruy | Time sênior | Todo o time |', 'step', 2),
    (v_sop_id, 4, 'Princípios Fundamentais', E'**1. Entrega com excelência** — Qualidade é inegociável. Se algo não está bom, dizemos antes de entregar.\n\n**2. Honestidade radical** — Dizemos o que pensamos, especialmente quando é difícil. Não prometemos o que não podemos entregar.\n\n**3. Responsabilidade sem desculpas** — Erros acontecem. Assumir o erro, propor solução e executar a correção é a resposta esperada — não a justificativa.\n\n**4. Confidencialidade como padrão** — Informações de clientes, projetos e preços são confidenciais por padrão. Se não foi dito que pode compartilhar, não compartilhe.\n\n**5. Respeito irrestrito** — Discriminação, assédio ou qualquer forma de desrespeito são incompatíveis com a TBO.', 'step', 3),
    (v_sop_id, 5, 'Condutas Esperadas e Inaceitáveis', E'**ESPERADAS:**\n- Entregar no prazo ou comunicar o risco com antecedência\n- Manter TBO OS atualizado (tarefas, status, projetos)\n- Pedir ajuda quando necessário — não deixar problema virar crise por omissão\n- Dar crédito ao trabalho alheio\n- Comunicar discordâncias de forma direta (não nos bastidores)\n\n**INACEITÁVEIS (causa de desligamento imediato):**\n- Assédio de qualquer natureza (moral, sexual, virtual)\n- Discriminação por gênero, raça, orientação sexual, religião ou origem\n- Desvio de cliente para concorrente ou empresa própria\n- Uso de informações confidenciais para benefício pessoal\n- Falsificação de dados, prazos ou entregas para o cliente\n- Conflito de interesse não declarado\n\n**GERAM ADVERTÊNCIA:**\n- Descumprimento reiterado de prazos sem comunicação\n- Comunicação agressiva com colegas\n- Não manter o TBO OS atualizado de forma sistemática', 'step', 4),
    (v_sop_id, 6, 'Checklist de Onboarding', E'- [ ] Colaborador leu e assinou o Termo de Ciência do Código de Conduta\n- [ ] Recebeu o link do formulário de relato anônimo\n- [ ] Marco ou Ruy apresentou os princípios em conversa de onboarding\n- [ ] Colaborador tem acesso ao TBO OS > Políticas\n- [ ] Termo assinado arquivado em Drive > RH > Políticas > Termos Assinados', 'checkpoint', 5),
    (v_sop_id, 7, 'Canal de Relato', E'Qualquer membro da TBO pode reportar uma violação:\n\n1. **Diretamente** para Marco ou Ruy (WhatsApp ou presencial)\n2. **E-mail**: conduta@agenciatbo.com.br (lido apenas por Marco e Ruy)\n3. **Anonimamente**: formulário no TBO OS > Políticas\n\n**Compromissos da TBO:**\n- Confidencialidade garantida para o relator\n- Investigação em até 5 dias úteis\n- Zero retaliação ao relator', 'tip', 6),
    (v_sop_id, 8, 'SLAs e Métricas', E'| Atividade | SLA |\n|---|---|\n| Apresentação do código no onboarding | 1º dia do colaborador |\n| Assinatura do Termo de Ciência | Até o fim da 1ª semana |\n| Resposta a relato de violação | Até 5 dias úteis |\n| Revisão anual do código | Janeiro de cada ano |\n| Comunicação da revisão ao time | Até 10 dias após a revisão |', 'note', 7),
    (v_sop_id, 9, 'Troubleshooting', E'**Colaborador não quer assinar o termo:**\n→ Explicar que a assinatura é ciência das regras, não concordância com punições\n→ Se recusa persistir: reportar a Marco antes de iniciar qualquer projeto\n\n**Situação ambígua (não está claro se é violação):**\n→ Regra de ouro: se você teria vergonha se Marco/Ruy soubessem, provavelmente é uma violação\n→ Em dúvida: perguntar diretamente antes de agir\n\n**Relato envolve um dos diretores:**\n→ Reportar ao outro diretor\n→ Se envolve ambos: acionar assessor jurídico externo (contato no TBO OS)', 'warning', 8),
    (v_sop_id, 10, 'Template: Termo de Ciência', E'```\nEu, [NOME COMPLETO], CPF [XXX.XXX.XXX-XX], declaro ter lido e compreendido\no Código de Conduta e Ética da TBO (versão [DATA]).\n\nEstou ciente de que as condutas inaceitáveis são causa de desligamento ou\nencerramento de contrato, independentemente de tempo de casa.\n\nMe comprometo a reportar violações que presenciar pelos canais indicados,\nsabendo que tenho garantia de confidencialidade e proteção contra retaliação.\n\nData: ___/___/______\nAssinatura: ___________________\n```', 'tip', 9);

  -- ══════════════════════════════════════════════════════════════════════════
  -- MELHORIA 4: Políticas — Propriedade Intelectual e Direitos Autorais
  -- ══════════════════════════════════════════════════════════════════════════
  INSERT INTO knowledge_sops (
    tenant_id, title, slug, bu, category, description, content, content_html,
    status, priority, tags, order_index, version
  ) VALUES (
    v_tenant_id,
    'Propriedade Intelectual e Direitos Autorais',
    'tbo-pol-003-propriedade-intelectual-e-direitos-autorais',
    'politicas',
    'referencia',
    'Política de propriedade intelectual da TBO: define titularidade de criações, cessão de direitos para clientes, uso de ativos de terceiros (fontes, imagens, plugins), proteção de portfólio e restrições de uso pós-contrato. Essencial para agência criativa — previne litígios e define regras claras com clientes e colaboradores.',
    E'## Propriedade Intelectual e Direitos Autorais — TBO\n\n### 1. Objetivo\nDefinir com clareza as regras de propriedade intelectual que regem as criações da TBO: quem possui o quê, quando ocorre a transferência de direitos ao cliente, como usar ativos de terceiros com segurança jurídica e como proteger o portfólio e o know-how da agência.\n\nPara uma agência criativa, propriedade intelectual é ativo central — tanto o que criamos para clientes quanto o que desenvolvemos internamente.\n\n### 2. Escopo\n**Quem se aplica:** Todos os colaboradores e freelancers da TBO, além dos contratos firmados com clientes\n**O que cobre:** Criações gráficas, renders 3D, vídeos, plataformas digitais, softwares internos, metodologias, templates e qualquer criação com cunho intelectual\n**Quando se aplica:** Em todo projeto, desde o briefing até o pós-entrega\n\n### 3. RACI\n\n| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Definir direitos no contrato | Ruy Lima | Marco | Assessor jurídico | Atendimento |\n| Verificar licenças de ativos de terceiros | Líder de BU | Marco | — | Colaborador |\n| Registrar criações estratégicas | Marco + Ruy | Marco + Ruy | Assessor jurídico | — |\n| Conceder uso de portfólio | Marco | — | Atendimento | — |\n| Auditar uso de ativos sem licença | Operações | Marco | Líder de BU | — |\n| Tratar violações de direitos por clientes | Ruy Lima | Marco | Assessor jurídico | — |\n\n### 4. Titularidade das Criações\n\n**4.1 O que a TBO possui (salvo contrato em contrário):**\n- Todo o processo criativo e intermediário (rascunhos, estudos, versões não aprovadas)\n- Metodologias, frameworks e processos internos desenvolvidos pela TBO\n- Templates, bibliotecas de materiais 3D, presets de iluminação e ativos reutilizáveis\n- Sistemas e softwares internos (TBO OS, plataformas desenvolvidas)\n- Direito de uso do projeto em portfólio\n\n**4.2 O que é cedido ao cliente (padrão contratual TBO):**\n- Arquivos finais aprovados nas versões entregues\n- Direito de uso comercial das peças aprovadas\n- Arquivos editáveis: apenas se contratado explicitamente (cobrado à parte)\n\n**4.3 O que NÃO é cedido automaticamente:**\n- Arquivos fonte (PSD, AI, .blend, .max, UE5 project) — apenas mediante contrato específico\n- Renders intermediários ou versões rejeitadas\n- Biblioteca de assets 3D da TBO (texturas, modelos, HDRIs)\n- Código-fonte de plataformas interativas — apenas licença de uso\n\n### 5. Regras de Uso de Ativos de Terceiros\n\n**ANTES de usar qualquer ativo externo, verificar a licença:**\n\n| Tipo de ativo | Licença aceitável | Licença PROIBIDA |\n|---|---|---|\n| Fontes tipográficas | Comercial (não apenas pessoal) | Free for personal use |\n| Fotos (stock) | Comercial, Extended (se impresso em larga escala) | Editorial only |\n| Modelos 3D | Comercial, sem restrição de uso |\nCC BY-NC (não comercial) |\n| Plugins/scripts | Licença de agência ou comercial | Trial ou licença pessoal |\n| Músicas para vídeo | Licença de sincronização | Royalty free sem licença |\n| IA generativa | Verificar ToS do serviço para uso comercial | Proibido para clientes sem verificação |\n\n**Regra de ouro:** Em caso de dúvida sobre licença, não usar. Consultar o Líder de BU.\n\n**Onde buscar ativos com licença garantida:**\n- Fontes: Google Fonts (OFL), Adobe Fonts (licença CC)\n- Fotos: Unsplash (livre), Envato Elements (licença TBO ativa), Adobe Stock\n- Modelos 3D: Quixel Megascans (licença Unreal), Turbosquid (verificar por item)\n- Músicas: Artlist.io (licença TBO ativa), Epidemic Sound\n\n### 6. Portfólio e Divulgação\n\n**A TBO tem direito de portfólio em todos os projetos**, salvo cláusula de confidencialidade expressa no contrato.\n\n**Regras para publicação:**\n- Verificar se há cláusula de confidencialidade ou embargo no contrato\n- Projetos de lançamento imobiliário: aguardar o lançamento público antes de publicar\n- Identificar o cliente e empreendimento apenas se ele autorizar nominalmente\n- Não publicar conteúdo que revele estratégia comercial do cliente\n\n**Aprovação para publicação:**\n1. Salvar assets de portfólio em `Drive > Portfólio TBO > [BU] > [Projeto]`\n2. Marcar como "liberado para publicação" ou "aguardando liberação"\n3. Para posts em redes sociais: aprovação de Marco ou Ruy antes de publicar\n\n### 7. Checklist de Projeto (verificação de PI)\n\n**Antes de iniciar qualquer projeto:**\n- [ ] Contrato assinado com cláusula de cessão de direitos clara\n- [ ] Todas as fontes usadas no projeto têm licença comercial verificada\n- [ ] Todos os assets de terceiros (fotos, modelos 3D, músicas) têm licença adequada\n\n**Antes de entregar ao cliente:**\n- [ ] Arquivos entregues são apenas os contratados (não incluir arquivos fonte sem contrato)\n- [ ] Assets da biblioteca interna da TBO não estão incluídos nos arquivos de entrega\n- [ ] Licenças de ativos adquiridos para o projeto foram transferidas ao cliente (se aplicável)\n\n**Para publicação de portfólio:**\n- [ ] Verificar embargo de lançamento (projeto de imóvel: aguardar lançamento)\n- [ ] Verificar cláusula de confidencialidade no contrato\n- [ ] Aprovação de Marco ou Ruy confirmada\n\n### 8. Ferramentas e Recursos\n\n- **Contratos**: Drive > Administrativo > Contratos > Template Padrão TBO (cláusulas de PI)\n- **Licenças ativas da TBO**: Drive > Administrativo > Licenças > Licenças Ativas 2026\n- **Portfólio**: Drive > Portfólio TBO > [BU] > [Projeto]\n- **Assessor jurídico**: contato no TBO OS > Contatos > Parceiros\n\n### 9. SLAs e Métricas\n\n| Atividade | SLA |\n|---|---|\n| Verificação de licença de ativo novo | Antes do uso (bloqueante) |\n| Resposta a questionamento de PI | Até 3 dias úteis |\n| Tratativa de violação de direitos por cliente | Até 10 dias úteis |\n| Revisão anual da política | Janeiro de cada ano |\n| Auditoria de licenças ativas | Anual (dezembro) |\n\n### 10. Troubleshooting\n\n**Cliente pede os arquivos fonte e não está no contrato:**\n→ Não enviar imediatamente — consultar Ruy Lima\n→ Verificar contrato: se não há previsão, negociar aditivo com valor adequado\n→ Arquivos fonte = know-how da TBO — preço deve refletir isso\n\n**Colaborador usou asset sem licença adequada:**\n→ Identificar todos os projetos onde o asset foi usado\n→ Adquirir licença retroativa se disponível\n→ Se não possível: substituir o asset e gerar nova versão do entregável\n→ Comunicar Ruy Lima para avaliar impacto com o cliente\n\n**Cliente reclama que usou o material de forma diferente do contratado:**\n→ Verificar o contrato: qual uso foi licenciado?\n→ Se uso diferente: informar que requer aditivo contratual\n→ Registrar no TBO OS: data, descrição do uso não autorizado\n→ Casos graves: acionar assessor jurídico\n\n**IA generativa: cliente quer usar conteúdo gerado por IA em material de marketing:**\n→ Verificar os termos de serviço da IA específica para uso comercial\n→ Midjourney, Dall-E, Firefly: verificar licença atual (muda frequentemente)\n→ Regra conservadora: IA generativa como referência/inspiração, não como entregável final sem validação jurídica\n\n### 11. Template Anexo\n\n**Cláusula padrão de PI para contratos TBO**\n```\nPROPRIEDADE INTELECTUAL\n\n1. A TBO é titular de todo o processo criativo, incluindo estudos, rascunhos\ne versões intermediárias não aprovadas.\n\n2. Ao cliente são cedidos, após pagamento integral, os direitos de uso\ncomercial das peças finais aprovadas, nas mídias e formatos especificados\nneste contrato.\n\n3. Não estão incluídos na cessão: arquivos editáveis (PSD, AI, .blend),\nbibliotecas de assets, código-fonte de plataformas digitais e qualquer\nativo de uso interno da TBO, salvo contratação específica e adicional.\n\n4. A TBO reserva-se o direito de utilizar os materiais produzidos em seu\nportfólio, salvo cláusula de confidencialidade expressa neste contrato.\n\n5. O cliente é responsável por garantir que os materiais da TBO sejam\nutilizados apenas nas mídias, formatos e territórios contratados.\nUso além do escopo requer aditivo contratual.\n```',
    '',
    'published',
    'critical',
    ARRAY['politicas', 'propriedade-intelectual', 'direitos-autorais', 'compliance', 'contratos', 'licencas', 'portfolio'],
    3,
    2
  )
  ON CONFLICT (tenant_id, slug) DO UPDATE SET
