    updated_at  = NOW();

  -- Steps para tbo-pol-003
  SELECT id INTO v_sop_id FROM knowledge_sops WHERE tenant_id = v_tenant_id AND slug = 'tbo-pol-003-propriedade-intelectual-e-direitos-autorais';
