  INSERT INTO knowledge_sop_steps (sop_id, step_number, title, content, step_type, order_index) VALUES
    (v_sop_id, 1, 'Objetivo', E'Definir com clareza as regras de propriedade intelectual que regem as criações da TBO: quem possui o quê, quando ocorre a transferência de direitos ao cliente, como usar ativos de terceiros com segurança jurídica e como proteger o portfólio da agência.\n\nPara uma agência criativa, propriedade intelectual é ativo central — tanto o que criamos para clientes quanto o que desenvolvemos internamente.', 'step', 0),
    (v_sop_id, 2, 'Escopo', E'**Quem se aplica:** Todos os colaboradores, freelancers e contratos com clientes\n**O que cobre:** Criações gráficas, renders 3D, vídeos, plataformas digitais, softwares internos, metodologias, templates\n**Quando se aplica:** Em todo projeto, desde o briefing até o pós-entrega', 'step', 1),
    (v_sop_id, 3, 'RACI', E'| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Definir direitos no contrato | Ruy Lima | Marco | Assessor jurídico | Atendimento |\n| Verificar licenças de ativos de terceiros | Líder de BU | Marco | — | Colaborador |\n| Registrar criações estratégicas | Marco + Ruy | Marco + Ruy | Assessor jurídico | — |\n| Conceder uso de portfólio | Marco | — | Atendimento | — |\n| Tratar violações por clientes | Ruy Lima | Marco | Assessor jurídico | — |', 'step', 2),
    (v_sop_id, 4, 'Titularidade das Criações', E'**A TBO possui (salvo contrato em contrário):**\n- Todo o processo criativo (rascunhos, estudos, versões não aprovadas)\n- Metodologias, frameworks e processos internos\n- Templates, bibliotecas de assets 3D, presets de iluminação\n- Sistemas internos (TBO OS, plataformas desenvolvidas)\n- Direito de portfólio em todos os projetos\n\n**Cedido ao cliente (padrão contratual):**\n- Arquivos finais aprovados nas versões entregues\n- Direito de uso comercial das peças aprovadas\n- Arquivos editáveis: apenas se contratado explicitamente (cobrado à parte)\n\n**NÃO cedido automaticamente:**\n- Arquivos fonte (PSD, AI, .blend, UE5 project)\n- Biblioteca de assets 3D da TBO\n- Código-fonte de plataformas interativas (apenas licença de uso)', 'step', 3),
    (v_sop_id, 5, 'Regras de Uso de Ativos de Terceiros', E'**ANTES de usar qualquer ativo externo, verificar a licença:**\n\n| Tipo de ativo | Licença aceitável | PROIBIDA |\n|---|---|---|\n| Fontes tipográficas | Comercial | Free for personal use |\n| Fotos (stock) | Comercial / Extended | Editorial only |\n| Modelos 3D | Comercial sem restrição | CC BY-NC (não comercial) |\n| Plugins/scripts | Comercial / agência | Trial ou pessoal |\n| Músicas para vídeo | Licença de sincronização | Royalty free sem licença |\n| IA generativa | Verificar ToS para uso comercial | Sem verificação jurídica |\n\n**Regra de ouro:** Em dúvida, não usar. Consultar o Líder de BU.\n\n**Fontes com licença garantida:**\n- Fontes: Google Fonts (OFL), Adobe Fonts\n- Fotos: Unsplash, Envato Elements (licença TBO), Adobe Stock\n- Modelos 3D: Quixel Megascans, Turbosquid (verificar por item)\n- Músicas: Artlist.io, Epidemic Sound (licenças TBO ativas)', 'step', 4),
    (v_sop_id, 6, 'Checklist de Verificação de PI', E'**Antes de iniciar o projeto:**\n- [ ] Contrato assinado com cláusula de cessão de direitos clara\n- [ ] Fontes tipográficas com licença comercial verificada\n- [ ] Todos os assets de terceiros (fotos, 3D, músicas) com licença adequada\n\n**Antes de entregar ao cliente:**\n- [ ] Entregando apenas o contratado (não incluir arquivos fonte sem contrato)\n- [ ] Assets da biblioteca interna TBO não incluídos na entrega\n- [ ] Licenças transferidas ao cliente se necessário\n\n**Para publicação de portfólio:**\n- [ ] Verificar embargo de lançamento (aguardar lançamento público para imóveis)\n- [ ] Verificar cláusula de confidencialidade no contrato\n- [ ] Aprovação de Marco ou Ruy confirmada', 'checkpoint', 5),
